// tests/fixtures/test_server.rs
// This becomes a binary that E2E tests can spawn

use fastmcp::Server;
use fastmcp_console::ConsoleConfig;

#[tokio::main]
async fn main() {
    let args: Vec<String> = std::env::args().collect();

    let config = ConsoleConfig::from_env();

    let mut server = Server::new("test-server")
        .version("1.0.0")
        .with_console_config(config)
        .tool(dummy_tool);

    if args.contains(&"--demo-mode".to_string()) {
        // Just show startup and exit
        server.display_startup();
        return;
    }

    if args.contains(&"--show-capabilities".to_string()) {
        server.display_capabilities();
        return;
    }

    if args.contains(&"--trigger-error".to_string()) {
        let idx = args.iter().position(|a| a == "--trigger-error").unwrap();
        let error_type = args.get(idx + 1).map(|s| s.as_str()).unwrap_or("generic");

        match error_type {
            "transport" => server.trigger_error(fastmcp::Error::Transport("test".into())),
            "timeout" => server.trigger_error(fastmcp::Error::Timeout(std::time::Duration::from_secs(30))),
            _ => server.trigger_error(fastmcp::Error::Internal("test".into())),
        }
        return;
    }

    // Normal operation
    server.run_stdio().await.unwrap();
}

#[fastmcp::tool]
fn dummy_tool(x: i32) -> i32 {
    x + 1
}
